import { createHash } from 'node:crypto';
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, '..');
const schemaDir = path.resolve(repoRoot, '../sb-publisher/schemas/flightdeck');
const outFile = path.resolve(repoRoot, 'src/generated/flightdeck-schema-bundle.js');

if (!fs.existsSync(schemaDir)) {
  if (fs.existsSync(outFile)) {
    console.log(`Schema source ${schemaDir} not found; using existing ${path.relative(repoRoot, outFile)}`);
    process.exit(0);
  }
  throw new Error(`Schema source ${schemaDir} not found and ${path.relative(repoRoot, outFile)} does not exist`);
}

function sortValue(value) {
  if (Array.isArray(value)) return value.map(sortValue);
  if (!value || typeof value !== 'object') return value;
  return Object.keys(value)
    .sort()
    .reduce((acc, key) => {
      acc[key] = sortValue(value[key]);
      return acc;
    }, {});
}

function canonicalJson(value) {
  return JSON.stringify(sortValue(value));
}

function readSchema(fileName) {
  const raw = fs.readFileSync(path.join(schemaDir, fileName), 'utf8');
  const manifest = JSON.parse(raw);
  const collectionSpace = String(
    manifest?.payload_schema?.properties?.collection_space?.const
    || fileName.replace(/-v\d+\.json$/, '')
  ).trim();
  const schemaVersion = Number(
    manifest?.compatibility?.schema_version
    || manifest?.payload_schema?.properties?.schema_version?.const
    || 1
  );
  return {
    collection_space: collectionSpace,
    schema_version: Number.isInteger(schemaVersion) && schemaVersion > 0 ? schemaVersion : 1,
    source_file: fileName,
    title: String(manifest.title || '').trim(),
    summary: String(manifest.summary || '').trim(),
    compatibility: manifest.compatibility || {},
    payload_schema: manifest.payload_schema,
  };
}

const files = fs.readdirSync(schemaDir)
  .filter((file) => /-v\d+\.json$/.test(file))
  .sort();

const schemas = files
  .map(readSchema)
  .sort((left, right) =>
    left.collection_space.localeCompare(right.collection_space)
    || left.schema_version - right.schema_version
    || left.source_file.localeCompare(right.source_file));

const schemaHash = createHash('sha256').update(canonicalJson(schemas), 'utf8').digest('hex');
const bundle = {
  bundle_schema_version: 1,
  schema_hash: schemaHash,
  schemas,
};

fs.mkdirSync(path.dirname(outFile), { recursive: true });
fs.writeFileSync(
  outFile,
  `// Generated by scripts/generate-flightdeck-schema-bundle.mjs\n`
  + `// Do not edit by hand.\n`
  + `export const FLIGHT_DECK_SCHEMA_BUNDLE = ${JSON.stringify(bundle, null, 2)};\n`,
);

console.log(`Wrote ${path.relative(repoRoot, outFile)} with ${schemas.length} schemas (${schemaHash})`);
